use strict;
use warnings;
use PDF::API2;
use Text::PDF::API2;

# Function to extract text from a page
sub extract_text {
    my ($page) = @_;
    my $text = '';
    my $content = $page->content;
    foreach my $line ($content->lines) {
        $text .= $line->text . "\n";
    }
    return $text;
}

# Function to process the PDF file
sub process_pdf {
    my ($filename) = @_;

    # Open the PDF file
    my $pdf = PDF::API2->open($filename);

    # Initialize variables to hold extracted data
    my ($date, $author, $table_data);

    # Loop through each page in the PDF
    for my $page_num (1 .. $pdf->pages) {
        my $page = $pdf->page($page_num);

        # Extract text from the page
        my $text = extract_text($page);

        # Process the text to extract the required information
        if ($text =~ /Date:\s*(\d{2}/\d{2}/\d{4})/) {
            $date = $1;
